  1→use std::collections::VecDeque;
  2→
  3→use cor24_emulator::{Assembler, EmulatorCore, StopReason};
  4→use gloo::timers::callback::Timeout;
  5→use web_sys::{HtmlInputElement, HtmlTextAreaElement, KeyboardEvent};
  6→use yew::prelude::*;
  7→
  8→use crate::config::{PreludeTier, StackSize};
  9→use crate::demos::DEMOS;
 10→
 11→/// Batch size per animation frame tick
 12→const BATCH_SIZE: u64 = 50_000;
 13→
 14→#[derive(Clone, Copy, PartialEq, Eq)]
 15→pub enum ViewMode {
 16→    Cli,
 17→    Split,
 18→}
 19→
 20→pub enum Msg {
 21→    Init,
 22→    Tick,
 23→    InputChanged(String),
 24→    Eval,
 25→    SetPrelude(PreludeTier),
 26→    SetStack(StackSize),
 27→    Reset,
 28→    LoadDemo(usize),
 29→    ToggleView,
 30→    ToggleSwitch,
 31→    ClearAll,
 32→    PauseResume,
 33→    /// Keydown in CLI input (Enter to eval)
 34→    CliKeyDown(KeyboardEvent),
 35→}
 36→
 37→pub struct Repl {
 38→    emulator: EmulatorCore,
 39→    /// Raw UART TX output from emulator (used by Split view)
 40→    output: String,
 41→    /// Interleaved transcript: UART output + echoed user input (used by CLI view)
 42→    transcript: String,
 43→    /// How many bytes of UART output we've already copied to transcript
 44→    uart_seen: usize,
 45→    input: String,
 46→    status: String,
 47→    running: bool,
 48→    loaded: bool,
 49→    waiting_for_input: bool,
 50→    uart_tx_queue: VecDeque<u8>,
 51→    prelude: PreludeTier,
 52→    stack_size: StackSize,
 53→    led_on: bool,
 54→    switch_pressed: bool,
 55→    view_mode: ViewMode,
 56→    selected_demo: Option<usize>,
 57→    /// Symbol addresses from assembly labels
 58→    addr_heap_next: Option<u32>,
 59→    addr_sym_count: Option<u32>,
 60→    addr_str_pool_next: Option<u32>,
 61→    /// Live memory readings
 62→    heap_used: u32,
 63→    sym_used: u32,
 64→    str_pool_used: u32,
 65→    stack_depth: u32,
 66→    /// Exponentially weighted CPU load (0.0 = idle, 1.0 = pegged)
 67→    cpu_load: f64,
 68→    input_ref: NodeRef,
 69→    cli_input_ref: NodeRef,
 70→}
 71→
 72→const HEAP_SIZE: u32 = 32768;
 73→const MAX_SYMBOLS: u32 = 512;
 74→const STR_POOL_SIZE: u32 = 8192;
 75→
 76→impl Repl {
 77→    fn load_binary(&mut self) {
 78→        let asm_source = self.prelude.assembly();
 79→        let mut asm = Assembler::new();
 80→        let result = asm.assemble(asm_source);
 81→
 82→        if !result.errors.is_empty() {
 83→            self.status = format!("Assembly failed: {}", result.errors[0]);
 84→            self.loaded = false;
 85→            return;
 86→        }
 87→
 88→        self.emulator.hard_reset();
 89→        self.emulator.set_uart_tx_busy_cycles(0); // instant TX in browser
 90→        for (addr, &byte) in result.bytes.iter().enumerate() {
 91→            self.emulator.write_byte(addr as u32, byte);
 92→        }
 93→        self.emulator.set_pc(0);
 94→        self.emulator.set_reg(4, self.stack_size.initial_sp());
 95→
 96→        // Capture memory pool addresses from symbol table
 97→        self.addr_heap_next = result.labels.get("_heap_next").copied();
 98→        self.addr_sym_count = result.labels.get("_sym_count").copied();
 99→        self.addr_str_pool_next = result.labels.get("_str_pool_next").copied();
100→
101→        self.output.clear();
102→        self.transcript.clear();
103→        self.uart_seen = 0;
104→        self.uart_tx_queue.clear();
105→        self.loaded = true;
106→        self.waiting_for_input = false;
107→        self.led_on = false;
108→        self.switch_pressed = false;
109→        self.heap_used = 0;
110→        self.sym_used = 0;
111→        self.str_pool_used = 0;
112→        self.stack_depth = 0;
113→        self.cpu_load = 0.0;
114→        self.status = format!(
115→            "Loaded {} bytes ({}, {} stack).",
116→            result.bytes.len(),
117→            self.prelude.label(),
118→            self.stack_size.label(),
119→        );
120→
121→        self.emulator.resume();
122→        self.running = true;
123→    }
124→
125→    fn view_gauge(&self, label: &str, used: u32, total: u32) -> Html {
126→        let pct = if total > 0 {
127→            (used as f64 / total as f64 * 100.0).min(100.0)
128→        } else {
129→            0.0
130→        };
131→        let color_class = if pct < 60.0 {
132→            "gauge-green"
133→        } else if pct < 85.0 {
134→            "gauge-yellow"
135→        } else {
136→            "gauge-red"
137→        };
138→        html! {
139→            <div class="gauge-row">
140→                <span class="gauge-label">{ label }</span>
141→                <div class="gauge-track">
142→                    <div class={classes!("gauge-fill", color_class)}
143→                         style={format!("width:{}%", pct)} />
144→                </div>
145→                <span class="gauge-text">{ format!("{}/{}", used, total) }</span>
146→            </div>
147→        }
148→    }
149→
150→    fn view_cpu_gauge(&self) -> Html {
151→        let pct = (self.cpu_load * 100.0).min(100.0);
152→        let color_class = if pct < 20.0 {
153→            "gauge-green"
154→        } else if pct < 60.0 {
155→            "gauge-yellow"
156→        } else {
157→            "gauge-red"
158→        };
159→        let label = if pct < 1.0 {
160→            "idle"
161→        } else if pct > 90.0 {
162→            "pegged"
163→        } else {
164→            "running"
165→        };
166→        html! {
167→            <div class="gauge-row">
168→                <span class="gauge-label">{ "CPU" }</span>
169→                <div class="gauge-track">
170→                    <div class={classes!("gauge-fill", color_class)}
171→                         style={format!("width:{}%", pct)} />
172→                </div>
173→                <span class="gauge-text">{ label }</span>
174→            </div>
175→        }
176→    }
177→
178→    fn send_input(&mut self) {
179→        for line in self.input.lines() {
180→            if line.trim().is_empty() {
181→                continue;
182→            }
183→            for byte in line.bytes() {
184→                self.uart_tx_queue.push_back(byte);
185→            }
186→            self.uart_tx_queue.push_back(b'\n');
187→        }
188→    }
189→}
190→
191→impl Component for Repl {
192→    type Message = Msg;
193→    type Properties = ();
194→
195→    fn create(ctx: &Context<Self>) -> Self {
196→        ctx.link().send_message(Msg::Init);
197→
198→        Self {
199→            emulator: {
200→                let mut emu = EmulatorCore::new();
201→                emu.set_uart_tx_busy_cycles(0); // instant TX in browser
202→                emu
203→            },
204→            output: String::new(),
205→            transcript: String::new(),
206→            uart_seen: 0,
207→            input: String::from("(+ 1 2)"),
208→            status: "Assembling interpreter...".into(),
209→            running: false,
210→            loaded: false,
211→            waiting_for_input: false,
212→            uart_tx_queue: VecDeque::new(),
213→            prelude: PreludeTier::Standard,
214→            stack_size: StackSize::ThreeKb,
215→            led_on: false,
216→            switch_pressed: false,
217→            view_mode: ViewMode::Cli,
218→            selected_demo: None,
219→            addr_heap_next: None,
220→            addr_sym_count: None,
221→            addr_str_pool_next: None,
222→            heap_used: 0,
223→            sym_used: 0,
224→            str_pool_used: 0,
225→            stack_depth: 0,
226→            cpu_load: 0.0,
227→            input_ref: NodeRef::default(),
228→            cli_input_ref: NodeRef::default(),
229→        }
230→    }
231→
232→    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
233→        match msg {
234→            Msg::Init => {
235→                self.load_binary();
236→                if self.loaded {
237→                    ctx.link().send_message(Msg::Tick);
238→                }
239→                true
240→            }
241→
242→            Msg::Tick => {
243→                if !self.running {
244→                    return false;
245→                }
246→
247→                // Feed queued bytes: poll-before-feed (match cor24-run).
248→                // Budget limits total instructions to avoid blocking the
249→                // browser when the interpreter is busy evaluating.
250→                let mut feed_budget: u32 = 10_000;
251→                while !self.uart_tx_queue.is_empty() && feed_budget > 0 {
252→                    let status = self.emulator.read_byte(0xFF0101);
253→                    if status & 0x01 != 0 {
254→                        // CPU hasn't consumed previous byte — run a bit more
255→                        self.emulator.run_batch(50);
256→                        feed_budget = feed_budget.saturating_sub(50);
257→                        continue;
258→                    }
259→                    let byte = self.uart_tx_queue.pop_front().unwrap();
260→                    self.emulator.send_uart_byte(byte);
261→                    self.emulator.run_batch(50);
262→                    feed_budget = feed_budget.saturating_sub(50);
263→                    if byte == b'\n' {
264→                        break;
265→                    }
266→                }
267→
268→                let result = self.emulator.run_batch(BATCH_SIZE);
269→
270→                // EWMA of CPU utilization: how much of the batch budget was used
271→                let utilization = result.instructions_run as f64 / BATCH_SIZE as f64;
272→                const ALPHA: f64 = 0.15; // smoothing factor
273→                self.cpu_load = self.cpu_load * (1.0 - ALPHA) + utilization * ALPHA;
274→
275→                if result.led_changed {
276→                    self.led_on = self.emulator.get_led() & 1 != 0;
277→                }
278→
279→                // Sample memory usage from runtime globals
280→                if let Some(addr) = self.addr_heap_next {
281→                    self.heap_used = self.emulator.read_word(addr);
282→                }
283→                if let Some(addr) = self.addr_sym_count {
284→                    self.sym_used = self.emulator.read_word(addr);
285→                }
286→                if let Some(addr) = self.addr_str_pool_next {
287→                    self.str_pool_used = self.emulator.read_word(addr);
288→                }
289→                let sp = self.emulator.get_reg(4);
290→                self.stack_depth = self.stack_size.initial_sp().saturating_sub(sp);
291→
292→                let uart = self.emulator.get_uart_output();
293→                // Append new UART bytes to transcript (CLI view)
294→                if uart.len() > self.uart_seen {
295→                    self.transcript.push_str(&uart[self.uart_seen..]);
296→                    self.uart_seen = uart.len();
297→                }
298→                // Update raw output (Split view)
299→                let uart_owned = uart.to_string();
300→                if uart_owned != self.output {
301→                    self.output = uart_owned;
302→                }
303→
304→                match result.reason {
305→                    StopReason::CycleLimit => {
306→                        let at_prompt =
307→                            self.uart_tx_queue.is_empty() && self.output.ends_with("> ");
308→
309→                        if at_prompt {
310→                            self.running = false;
311→                            self.waiting_for_input = true;
312→                            self.cpu_load = 0.0;
313→                            self.status = "Ready.".into();
314→                        } else {
315→                            let link = ctx.link().clone();
316→                            Timeout::new(25, move || link.send_message(Msg::Tick)).forget();
317→                        }
318→                    }
319→                    StopReason::Halted => {
320→                        self.running = false;
321→                        self.waiting_for_input = false;
322→                        self.cpu_load = 0.0;
323→                        self.status = "Program finished.".into();
324→                    }
325→                    StopReason::InvalidInstruction(byte) => {
326→                        self.running = false;
327→                        self.status = format!(
328→                            "Invalid instruction 0x{:02X} at PC=0x{:06X}",
329→                            byte,
330→                            self.emulator.pc()
331→                        );
332→                    }
333→                    StopReason::Breakpoint(addr) => {
334→                        self.running = false;
335→                        self.status = format!("Breakpoint at 0x{:06X}", addr);
336→                    }
337→                    StopReason::Paused => {
338→                        self.running = false;
339→                        self.status = "Paused.".into();
340→                    }
341→                }
342→                true
343→            }
344→
345→            Msg::InputChanged(value) => {
346→                self.input = value;
347→                false
348→            }
349→
350→            Msg::Eval => {
351→                if !self.loaded {
352→                    return true;
353→                }
354→                // Echo input to transcript (CLI view shows interleaved I/O)
355→                for line in self.input.lines() {
356→                    if !line.trim().is_empty() {
357→                        self.transcript.push_str(line);
358→                        self.transcript.push('\n');
359→                    }
360→                }
361→                self.send_input();
362→                self.status = "Evaluating...".into();
363→                self.waiting_for_input = false;
364→                if !self.running {
365→                    self.emulator.resume();
366→                    self.running = true;
367→                    ctx.link().send_message(Msg::Tick);
368→                }
369→                // In CLI mode, clear the input after sending
370→                if self.view_mode == ViewMode::Cli {
371→                    self.input.clear();
372→                }
373→                true
374→            }
375→
376→            Msg::CliKeyDown(e) => {
377→                if e.key() == "Enter" && !e.shift_key() {
378→                    e.prevent_default();
379→                    ctx.link().send_message(Msg::Eval);
380→                }
381→                false
382→            }
383→
384→            Msg::SetPrelude(tier) => {
385→                if tier != self.prelude {
386→                    self.prelude = tier;
387→                    self.running = false;
388→                    self.load_binary();
389→                    if self.loaded {
390→                        ctx.link().send_message(Msg::Tick);
391→                    }
392→                }
393→                true
394→            }
395→
396→            Msg::SetStack(size) => {
397→                if size != self.stack_size {
398→                    self.stack_size = size;
399→                    self.running = false;
400→                    self.load_binary();
401→                    if self.loaded {
402→                        ctx.link().send_message(Msg::Tick);
403→                    }
404→                }
405→                true
406→            }
407→
408→            Msg::Reset => {
409→                self.running = false;
410→                self.load_binary();
411→                if self.loaded {
412→                    ctx.link().send_message(Msg::Tick);
413→                }
414→                true
415→            }
416→
417→            Msg::LoadDemo(index) => {
418→                if let Some(demo) = DEMOS.get(index) {
419→                    self.selected_demo = Some(index);
420→                    self.input = demo.source.trim().to_string();
421→                    self.prelude = demo.prelude;
422→                    self.stack_size = demo.stack;
423→                    // Always reset emulator for a clean demo run
424→                    self.running = false;
425→                    self.load_binary();
426→                    if self.loaded {
427→                        ctx.link().send_message(Msg::Tick);
428→                    }
429→                    // Switch to Split view for demos (multi-line code)
430→                    self.view_mode = ViewMode::Split;
431→                }
432→                true
433→            }
434→
435→            Msg::ToggleView => {
436→                self.view_mode = match self.view_mode {
437→                    ViewMode::Cli => ViewMode::Split,
438→                    ViewMode::Split => ViewMode::Cli,
439→                };
440→                true
441→            }
442→
443→            Msg::ToggleSwitch => {
444→                self.switch_pressed = !self.switch_pressed;
445→                self.emulator.set_button_pressed(self.switch_pressed);
446→                true
447→            }
448→
449→            Msg::ClearAll => {
450→                self.emulator.clear_uart_output();
451→                self.output.clear();
452→                self.transcript.clear();
453→                self.uart_seen = 0;
454→                self.input.clear();
455→                self.selected_demo = None;
456→                true
457→            }
458→
459→            Msg::PauseResume => {
460→                if self.running {
461→                    // Pause
462→                    self.running = false;
463→                    self.status = "Paused.".into();
464→                } else if self.loaded {
465→                    // Resume
466→                    self.emulator.resume();
467→                    self.running = true;
468→                    self.waiting_for_input = false;
469→                    self.status = "Running...".into();
470→                    ctx.link().send_message(Msg::Tick);
471→                }
472→                true
473→            }
474→        }
475→    }
476→
477→    fn view(&self, ctx: &Context<Self>) -> Html {
478→        let on_eval = ctx.link().callback(|_| Msg::Eval);
479→        let on_reset = ctx.link().callback(|_| Msg::Reset);
480→        let on_toggle_view = ctx.link().callback(|_| Msg::ToggleView);
481→        let on_toggle_switch = ctx.link().callback(|_| Msg::ToggleSwitch);
482→        let on_clear = ctx.link().callback(|_| Msg::ClearAll);
483→        let on_pause = ctx.link().callback(|_| Msg::PauseResume);
484→
485→        let on_prelude = ctx.link().callback(|e: Event| {
486→            let target: web_sys::HtmlSelectElement = e.target_unchecked_into();
487→            let tier = match target.value().as_str() {
488→                "bare" => PreludeTier::Bare,
489→                "minimal" => PreludeTier::Minimal,
490→                "full" => PreludeTier::Full,
491→                "scheme" => PreludeTier::Scheme,
492→                _ => PreludeTier::Standard,
493→            };
494→            Msg::SetPrelude(tier)
495→        });
496→
497→        let on_stack = ctx.link().callback(|e: Event| {
498→            let target: web_sys::HtmlSelectElement = e.target_unchecked_into();
499→            let size = match target.value().as_str() {
500→                "8" => StackSize::EightKb,
501→                _ => StackSize::ThreeKb,
502→            };
503→            Msg::SetStack(size)
504→        });
505→
506→        let on_demo = ctx.link().callback(|e: Event| {
507→            let target: web_sys::HtmlSelectElement = e.target_unchecked_into();
508→            let idx: usize = target.value().parse().unwrap_or(usize::MAX);
509→            Msg::LoadDemo(idx)
510→        });
511→
512→        let eval_disabled = (!self.waiting_for_input && self.running) || !self.loaded;
513→        let show_spinner = self.running && !self.waiting_for_input;
514→        let view_label = match self.view_mode {
515→            ViewMode::Cli => "Split",
516→            ViewMode::Split => "CLI",
517→        };
518→
519→        html! {
520→            <div class="repl-container">
521→                // Toolbar
522→                <div class="toolbar">
523→                    <label class="toolbar-item">
524→                        {"Prelude"}
525→                        <select onchange={on_prelude}>
526→                            { for PreludeTier::ALL.iter().map(|t| {
527→                                let val = match t {
528→                                    PreludeTier::Bare => "bare",
529→                                    PreludeTier::Minimal => "minimal",
530→                                    PreludeTier::Standard => "standard",
531→                                    PreludeTier::Full => "full",
532→                                    PreludeTier::Scheme => "scheme",
533→                                };
534→                                html! {
535→                                    <option value={val} selected={*t == self.prelude}>
536→                                        { t.label() }
537→                                    </option>
538→                                }
539→                            })}
540→                        </select>
541→                    </label>
542→                    <label class="toolbar-item">
543→                        {"Stack"}
544→                        <select onchange={on_stack}>
545→                            { for StackSize::ALL.iter().map(|s| {
546→                                let val = match s {
547→                                    StackSize::ThreeKb => "3",
548→                                    StackSize::EightKb => "8",
549→                                };
550→                                html! {
551→                                    <option value={val} selected={*s == self.stack_size}>
552→                                        { s.label() }
553→                                    </option>
554→                                }
555→                            })}
556→                        </select>
557→                    </label>
558→                    <label class="toolbar-item">
559→                        {"Demo"}
560→                        <select onchange={on_demo}>
561→                            <option value="" selected={self.selected_demo.is_none()}>{"— select —"}</option>
562→                            { for PreludeTier::ALL.iter().filter(|tier| {
563→                                DEMOS.iter().any(|d| d.prelude == **tier)
564→                            }).map(|tier| {
565→                                let label = format!("{} prelude", tier.label());
566→                                html! {
567→                                    <optgroup label={label}>
568→                                        { for DEMOS.iter().enumerate()
569→                                            .filter(move |(_, d)| d.prelude == *tier)
570→                                            .map(|(i, d)| {
571→                                                let stack_note = if d.stack == StackSize::EightKb {
572→                                                    " [8K]"
573→                                                } else {
574→                                                    ""
575→                                                };
576→                                                let sel = self.selected_demo == Some(i);
577→                                                html! {
578→                                                    <option value={i.to_string()} selected={sel}>
579→                                                        { format!("{}{}", d.title, stack_note) }
580→                                                    </option>
581→                                                }
582→                                            })
583→                                        }
584→                                    </optgroup>
585→                                }
586→                            })}
587→                        </select>
588→                    </label>
589→                    <button class="toolbar-btn" onclick={on_toggle_view}>{ view_label }</button>
590→                    <button class="toolbar-btn" onclick={on_pause}>
591→                        { if self.running { "Pause" } else { "Resume" } }
592→                    </button>
593→                    <button class="toolbar-btn" onclick={on_reset}>{"Reset"}</button>
594→                    <button class="toolbar-btn" onclick={on_clear}>{"Clear"}</button>
595→                    <span class="toolbar-desc">{ self.prelude.description() }</span>
596→                </div>
597→
598→                // Main area (output is always full-size)
599→                <div class="main-area">
600→                    // Output panel (full size)
601→                    // CLI view: interleaved transcript; Split view: raw UART output
602→                    <pre class="output">{ match self.view_mode {
603→                        ViewMode::Cli => &self.transcript,
604→                        ViewMode::Split => &self.output,
605→                    }}</pre>
606→
607→                    // Floating hardware + memory panel (top-right)
608→                    <div class="hw-float">
609→                        <div class="hw-row">
610→                            <span class="hw-label">{"D2"}</span>
611→                            <div class={if self.led_on { "led led-on" } else { "led led-off" }} />
612→                        </div>
613→                        <div class="hw-row">
614→                            <span class="hw-label">{"S2"}</span>
615→                            <div class={if self.switch_pressed { "switch switch-on" } else { "switch switch-off" }}
616→                                 onclick={on_toggle_switch} />
617→                        </div>
618→                        <div class="hw-sep" />
619→                        { self.view_cpu_gauge() }
620→                        { self.view_gauge("Heap", self.heap_used, HEAP_SIZE) }
621→                        { self.view_gauge("Syms", self.sym_used, MAX_SYMBOLS) }
622→                        { self.view_gauge("Strs", self.str_pool_used, STR_POOL_SIZE) }
623→                        { self.view_gauge("Stack", self.stack_depth, self.stack_size.bytes()) }
624→                    </div>
625→
626→                    // Input area depends on view mode
627→                    { match self.view_mode {
628→                        ViewMode::Cli => {
629→                            let on_cli_input = ctx.link().callback(|e: InputEvent| {
630→                                let target: HtmlInputElement = e.target_unchecked_into();
631→                                Msg::InputChanged(target.value())
632→                            });
633→                            let on_keydown = ctx.link().callback(Msg::CliKeyDown);
634→                            html! {
635→                                <div class="cli-input-bar">
636→                                    <span class="cli-prompt">{"> "}</span>
637→                                    <input
