430→    // ===== Disassembly =====
431→
432→    /// Disassemble one instruction at the given address.
433→    /// Returns (mnemonic_string, instruction_size_in_bytes).
434→    pub fn disassemble_at(&self, addr: u32) -> (String, u32) {
435→        use crate::cpu::instruction::{InstructionFormat, reg_name};
436→
437→        let inst_byte = self.cpu.read_byte(addr);
438→        let decoded = self.decode_rom.decode(inst_byte);
439→        if decoded == 0xFFF {
440→            return (format!(".byte 0x{:02X}", inst_byte), 1);
441→        }
442→
443→        let inst = DecodedInstruction::from_decoded(decoded);
444→        let format = inst.opcode.format();
445→        let size = match format {
446→            InstructionFormat::SingleByte => 1,
447→            InstructionFormat::TwoBytes => 2,
448→            InstructionFormat::FourBytes => 4,
449→        };
450→
451→        let text = match format {
452→            InstructionFormat::SingleByte => match inst.opcode {
453→                Opcode::Pop => format!("pop  {}", reg_name(inst.ra)),
454→                Opcode::Push => format!("push {}", reg_name(inst.ra)),
455→                Opcode::Jmp => format!("jmp  ({})", reg_name(inst.ra)),
456→                Opcode::Jal => {
457→                    format!("jal  {},({})", reg_name(inst.ra), reg_name(inst.rb))
458→                }
459→                Opcode::Mov if inst.rb == 5 => {
460→                    format!("mov  {},c", reg_name(inst.ra))
461→                }
462→                _ => {
463→                    format!(
464→                        "{:4} {},{}",
465→                        inst.opcode.mnemonic(),
466→                        reg_name(inst.ra),
467→                        reg_name(inst.rb)
468→                    )
469→                }
470→            },
471→            InstructionFormat::TwoBytes => {
472→                let imm = self.cpu.read_byte(addr + 1);
473→                let signed = imm as i8;
474→                match inst.opcode {
475→                    Opcode::Bra | Opcode::Brf | Opcode::Brt => {
476→                        let branch_base = addr.wrapping_add(4);
477→                        let target = CpuState::mask_24(
478→                            branch_base.wrapping_add(CpuState::sign_extend_8(imm)),
479→                        );
480→                        format!("{:4} 0x{:06X}", inst.opcode.mnemonic(), target)
481→                    }
482→                    Opcode::Lc | Opcode::Lcu | Opcode::AddImm => {
483→                        format!(
484→                            "{:4} {},{}",
485→                            inst.opcode.mnemonic(),
486→                            reg_name(inst.ra),
487→                            signed
488→                        )
489→                    }
490→                    _ => {
491→                        // Lb, Lbu, Lw, Sb, Sw with offset
492→                        if signed == 0 {
493→                            format!(
494→                                "{:4} {},({})",
495→                                inst.opcode.mnemonic(),
496→                                reg_name(inst.ra),
497→                                reg_name(inst.rb)
498→                            )
499→                        } else {
500→                            format!(
501→                                "{:4} {},{}({})",
502→                                inst.opcode.mnemonic(),
503→                                reg_name(inst.ra),
504→                                signed,
505→                                reg_name(inst.rb)
506→                            )
507→                        }
508→                    }
509→                }
510→            }
511→            InstructionFormat::FourBytes => {
512→                let b0 = self.cpu.read_byte(addr + 1) as u32;
513→                let b1 = self.cpu.read_byte(addr + 2) as u32;
514→                let b2 = self.cpu.read_byte(addr + 3) as u32;
515→                let imm24 = b0 | (b1 << 8) | (b2 << 16);
516→                format!(
517→                    "{:4} {},0x{:06X}",
518→                    inst.opcode.mnemonic(),
519→                    reg_name(inst.ra),
520→                    imm24
521→                )
522→            }
523→        };
524→
525→        (text, size)
526→    }
527→
528→    /// Disassemble N instructions starting at addr
529→    pub fn disassemble(&self, addr: u32, count: usize) -> Vec<(u32, String, u32)> {
530→        let mut result = Vec::with_capacity(count);
531→        let mut pc = addr;
532→        for _ in 0..count {
533→            let (text, size) = self.disassemble_at(pc);
534→            result.push((pc, text, size));
535→            pc = CpuState::mask_24(pc + size);
536→        }
537→        result
538→    }
539→}
