168→impl TraceEntry {
169→    /// Disassemble this instruction into a human-readable string
170→    pub fn disassemble(&self) -> String {
171→        let ra = REG_NAMES[self.ra as usize];
172→        let rb = REG_NAMES[self.rb as usize];
173→        match self.opcode {
174→            Opcode::AddReg => format!("add     {},{}", ra, rb),
175→            Opcode::AddImm => format!("add     {},{}", ra, self.imm8 as i8),
176→            Opcode::And => format!("and     {},{}", ra, rb),
177→            Opcode::Bra => {
178→                let offset = self.imm8 as i8;
179→                let target = (self.pc as i64 + 4 + offset as i64) as u32 & 0xFFFFFF;
180→                format!("bra     0x{:06X}", target)
181→            }
182→            Opcode::Brf => {
183→                let offset = self.imm8 as i8;
184→                let target = (self.pc as i64 + 4 + offset as i64) as u32 & 0xFFFFFF;
185→                format!("brf     0x{:06X}", target)
186→            }
187→            Opcode::Brt => {
188→                let offset = self.imm8 as i8;
189→                let target = (self.pc as i64 + 4 + offset as i64) as u32 & 0xFFFFFF;
190→                format!("brt     0x{:06X}", target)
191→            }
192→            Opcode::Ceq => format!("ceq     {},{}", ra, rb),
193→            Opcode::Cls => format!("cls     {},{}", ra, rb),
194→            Opcode::Clu => format!("clu     {},{}", ra, rb),
195→            Opcode::Jal => format!("jal     {},({})", ra, rb),
196→            Opcode::Jmp => format!("jmp     ({})", ra),
197→            Opcode::La => format!("la      {},0x{:06X}", ra, self.imm24),
198→            Opcode::Lb => format!("lb      {},{}({})", ra, self.imm8 as i8, rb),
199→            Opcode::Lbu => format!("lbu     {},{}({})", ra, self.imm8, rb),
200→            Opcode::Lc => format!("lc      {},{}", ra, self.imm8 as i8),
201→            Opcode::Lcu => format!("lcu     {},{}", ra, self.imm8),
202→            Opcode::Lw => format!("lw      {},{}({})", ra, self.imm8 as i8, rb),
203→            Opcode::Mov => format!("mov     {},{}", ra, rb),
204→            Opcode::Mul => format!("mul     {},{}", ra, rb),
205→            Opcode::Or => format!("or      {},{}", ra, rb),
206→            Opcode::Pop => format!("pop     {}", ra),
207→            Opcode::Push => format!("push    {}", ra),
208→            Opcode::Sb => format!("sb      {},{}({})", ra, self.imm8 as i8, rb),
209→            Opcode::Shl => format!("shl     {},{}", ra, rb),
210→            Opcode::Sra => format!("sra     {},{}", ra, rb),
211→            Opcode::Srl => format!("srl     {},{}", ra, rb),
212→            Opcode::Sub => format!("sub     {},{}", ra, rb),
213→            Opcode::SubSp => format!("sub     sp,{}", self.imm24),
214→            Opcode::Sw => format!("sw      {},{}({})", ra, self.imm8 as i8, rb),
215→            Opcode::Sxt => format!("sxt     {},{}", ra, rb),
216→            Opcode::Xor => format!("xor     {},{}", ra, rb),
217→            Opcode::Zxt => format!("zxt     {},{}", ra, rb),
218→            Opcode::Invalid => format!("??? (0x{:02X})", self.imm8),
219→        }
220→    }
221→}
