223→/// Ring buffer of recent instruction trace entries
224→#[derive(Clone)]
225→pub struct TraceBuffer {
226→    entries: Vec<TraceEntry>,
227→    head: usize,
228→    capacity: usize,
229→    count: usize,
230→}
231→
232→impl Default for TraceBuffer {
233→    fn default() -> Self {
234→        Self::new(200)
235→    }
236→}
237→
238→impl TraceBuffer {
239→    /// Create a new trace buffer with given capacity
240→    pub fn new(capacity: usize) -> Self {
241→        Self {
242→            entries: Vec::with_capacity(capacity),
243→            head: 0,
244→            capacity,
245→            count: 0,
246→        }
247→    }
248→
249→    /// Record a trace entry
250→    pub fn push(&mut self, entry: TraceEntry) {
251→        if self.entries.len() < self.capacity {
252→            self.entries.push(entry);
253→        } else {
254→            self.entries[self.head] = entry;
255→        }
256→        self.head = (self.head + 1) % self.capacity;
257→        self.count += 1;
258→    }
259→
260→    /// Get the last N entries in chronological order
261→    pub fn last_n(&self, n: usize) -> Vec<&TraceEntry> {
262→        let len = self.entries.len();
263→        let n = n.min(len);
264→        let mut result = Vec::with_capacity(n);
265→        for i in 0..n {
266→            let idx = if len < self.capacity {
267→                // Not yet wrapped
268→                len - n + i
269→            } else {
270→                (self.head + self.capacity - n + i) % self.capacity
271→            };
272→            result.push(&self.entries[idx]);
273→        }
274→        result
275→    }
276→
277→    /// Get all entries in chronological order
278→    pub fn all(&self) -> Vec<&TraceEntry> {
279→        self.last_n(self.entries.len())
280→    }
281→
282→    /// Total number of entries ever recorded
283→    pub fn total_count(&self) -> usize {
284→        self.count
285→    }
286→
287→    /// Number of entries currently in buffer
288→    pub fn len(&self) -> usize {
289→        self.entries.len()
290→    }
291→
292→    /// Check if buffer is empty
293→    pub fn is_empty(&self) -> bool {
294→        self.entries.is_empty()
295→    }
296→
297→    /// Clear all entries
298→    pub fn clear(&mut self) {
299→        self.entries.clear();
300→        self.head = 0;
301→        self.count = 0;
302→    }
303→
304→    /// Format the last N entries as a multi-line string
305→    pub fn format_last(&self, n: usize) -> String {
306→        let entries = self.last_n(n);
307→        let mut out = String::new();
308→        out.push_str(&format!(
309→            "--- Trace (last {} of {} total) ---\n",
310→            entries.len(),
311→            self.count
312→        ));
313→        out.push_str(&format!(
314→            "{:>5} {:>8}  {:<24}  {}\n",
315→            "#", "PC", "Instruction", "Changes"
316→        ));
317→        for entry in &entries {
318→            out.push_str(&format!("{}\n", entry));
319→        }
320→        out
321→    }
322→}
