324→/// COR24 CPU state
325→#[derive(Clone, Serialize, Deserialize)]
326→pub struct CpuState {
327→    /// Program counter (24-bit)
328→    pub pc: u32,
329→    /// Register file (8 x 24-bit registers)
330→    pub registers: [u32; 8],
331→    /// Condition flag (NOT carry — set by ceq/cls/clu, tested by brt/brf)
332→    pub c: bool,
333→    /// SRAM (1 MB, 0x000000-0x0FFFFF)
334→    pub memory: Vec<u8>,
335→    /// Embedded Block RAM (8 KB, mapped at 0xFEE000-0xFEFFFF)
336→    pub ebr: Vec<u8>,
337→    /// Halted flag
338→    pub halted: bool,
339→    /// Interrupt-in-service flag (prevents nested interrupts)
340→    pub intis: bool,
341→    /// Cycle count
342→    pub cycles: u64,
343→    /// Instruction count
344→    pub instructions: u64,
345→    /// I/O peripheral state
346→    pub io: IoState,
347→    /// Instruction execution trace (ring buffer, not serialized)
348→    #[serde(skip)]
349→    pub trace: TraceBuffer,

150→                // Detect self-branch (halt: bra halt) as halt condition
151→                let instruction_addr = CpuState::mask_24(next_pc.wrapping_sub(2));
152→                if target == instruction_addr {
153→                    cpu.pc = instruction_addr;
154→                    cpu.halted = true;
155→                    halted_by_self_branch = true;
156→                } else {
157→                    cpu.pc = target;
158→                }
159→            }
160→
161→            Opcode::Brf => {
162→                // brf dd (branch if false)
163→                if !cpu.c {
164→                    let offset = CpuState::sign_extend_8(imm8);
165→                    let branch_base = next_pc.wrapping_add(2);
166→                    cpu.pc = CpuState::mask_24(branch_base.wrapping_add(offset));
167→                } else {
168→                    cpu.pc = next_pc;
169→                }
170→            }
171→
172→            Opcode::Brt => {
173→                // brt dd (branch if true)
174→                if cpu.c {
175→                    let offset = CpuState::sign_extend_8(imm8);
176→                    let branch_base = next_pc.wrapping_add(2);
177→                    cpu.pc = CpuState::mask_24(branch_base.wrapping_add(offset));
178→                } else {
179→                    cpu.pc = next_pc;
180→                }
181→            }
182→
183→            Opcode::Ceq => {
184→                // ceq ra,rb (compare equal)
185→                let ra_val = cpu.get_reg(inst.ra);
186→                let rb_val = cpu.get_reg(inst.rb);
187→                cpu.c = ra_val == rb_val;
188→                cpu.pc = next_pc;
189→            }
190→
191→            Opcode::Cls => {
192→                // cls ra,rb (compare less signed)
193→                let ra_val = cpu.get_reg(inst.ra) as i32;
194→                let rb_val = cpu.get_reg(inst.rb) as i32;
195→                // Sign extend from 24-bit
196→                let ra_signed = if ra_val & 0x800000 != 0 {
197→                    ra_val | 0xFF000000u32 as i32
198→                } else {
199→                    ra_val
200→                };
201→                let rb_signed = if rb_val & 0x800000 != 0 {
202→                    rb_val | 0xFF000000u32 as i32
203→                } else {
204→                    rb_val
205→                };
206→                cpu.c = ra_signed < rb_signed;
207→                cpu.pc = next_pc;
208→            }
209→
210→            Opcode::Clu => {
211→                // clu ra,rb (compare less unsigned)
212→                let ra_val = cpu.get_reg(inst.ra);
213→                let rb_val = cpu.get_reg(inst.rb);
214→                cpu.c = ra_val < rb_val;
215→                cpu.pc = next_pc;
216→            }
217→
218→            Opcode::Jal => {
219→                // jal ra,(rb) - jump and link
220→                let target = cpu.get_reg(inst.rb);
221→                cpu.set_reg(inst.ra, next_pc);
222→                cpu.pc = target;
223→            }
224→
225→            Opcode::Jmp => {
226→                // jmp (ra)
227→                let target = cpu.get_reg(inst.ra);
228→                // jmp (r7) clears interrupt-in-service flag (hardware: &racode)
229→                if inst.ra == 7 {
230→                    cpu.intis = false;
231→                }
232→                cpu.pc = target;
233→            }
234→
235→            Opcode::La => {
236→                // la ra,dddddd
237→                if inst.ra == 7 {
238→                    // jmp dddddd (absolute jump)
239→                    cpu.pc = imm24;
240→                } else {
241→                    cpu.set_reg(inst.ra, imm24);
242→                    cpu.pc = next_pc;
243→                }
244→            }
245→
246→            Opcode::Lb => {
247→                // lb ra,dd(rb) - load byte signed
248→                let base = cpu.get_reg(inst.rb);
249→                let offset = CpuState::sign_extend_8(imm8);
250→                let addr = CpuState::mask_24(base.wrapping_add(offset));
251→                let value = cpu.read_byte_exec(addr);
252→                cpu.set_reg(inst.ra, CpuState::sign_extend_8(value));
253→                cpu.pc = next_pc;
254→            }
255→
256→            Opcode::Lbu => {
257→                // lbu ra,dd(rb) - load byte unsigned
258→                let base = cpu.get_reg(inst.rb);
259→                let offset = CpuState::sign_extend_8(imm8);
260→                let addr = CpuState::mask_24(base.wrapping_add(offset));
261→                let value = cpu.read_byte_exec(addr);
262→                cpu.set_reg(inst.ra, value as u32);
263→                cpu.pc = next_pc;
264→            }
265→
266→            Opcode::Lc => {
267→                // lc ra,dd - load constant signed
268→                cpu.set_reg(inst.ra, CpuState::sign_extend_8(imm8));
269→                cpu.pc = next_pc;
270→            }
271→
272→            Opcode::Lcu => {
273→                // lcu ra,dd - load constant unsigned
274→                cpu.set_reg(inst.ra, imm8 as u32);
275→                cpu.pc = next_pc;
276→            }
277→
278→            Opcode::Lw => {
279→                // lw ra,dd(rb) - load word
280→                let base = cpu.get_reg(inst.rb);
281→                let offset = CpuState::sign_extend_8(imm8);
282→                let addr = CpuState::mask_24(base.wrapping_add(offset));
283→                let value = cpu.read_word(addr);
284→                cpu.set_reg(inst.ra, value);
285→                cpu.pc = next_pc;
286→            }
287→
288→            Opcode::Mov => {
289→                // mov ra,rb or mov ra,c
290→                if inst.rb == 5 {
291→                    // mov ra,c
292→                    cpu.set_reg(inst.ra, if cpu.c { 1 } else { 0 });
293→                } else {
294→                    cpu.set_reg(inst.ra, cpu.get_reg(inst.rb));
295→                }
296→                cpu.pc = next_pc;
297→            }
298→
299→            Opcode::Mul => {
300→                // mul ra,rb
301→                let ra_val = cpu.get_reg(inst.ra);
302→                let rb_val = cpu.get_reg(inst.rb);
303→                let result = CpuState::mask_24(ra_val.wrapping_mul(rb_val));
304→                cpu.set_reg(inst.ra, result);
305→                cpu.pc = next_pc;
306→            }
307→
308→            Opcode::Or => {
309→                // or ra,rb
310→                let ra_val = cpu.get_reg(inst.ra);
311→                let rb_val = cpu.get_reg(inst.rb);
312→                cpu.set_reg(inst.ra, ra_val | rb_val);
313→                cpu.pc = next_pc;
314→            }
315→
316→            Opcode::Pop => {
317→                // pop ra - load from stack, increment sp
318→                let sp = cpu.get_reg(4);
319→                let value = cpu.read_word(sp);
320→                cpu.set_reg(inst.ra, value);
321→                cpu.set_reg(4, CpuState::mask_24(sp.wrapping_add(3)));
322→                cpu.pc = next_pc;
323→            }
324→
325→            Opcode::Push => {
326→                // push ra - decrement sp, store to stack
327→                let sp = cpu.get_reg(4);
328→                let new_sp = CpuState::mask_24(sp.wrapping_sub(3));
329→                cpu.set_reg(4, new_sp);
330→                let value = cpu.get_reg(inst.ra);
331→                cpu.write_word(new_sp, value);
332→                cpu.pc = next_pc;
333→            }
334→
335→            Opcode::Sb => {
336→                // sb ra,dd(rb) - store byte
337→                let base = cpu.get_reg(inst.rb);
338→                let offset = CpuState::sign_extend_8(imm8);
339→                let addr = CpuState::mask_24(base.wrapping_add(offset));
340→                let value = cpu.get_reg(inst.ra) as u8;
341→                cpu.write_byte(addr, value);
342→                cpu.pc = next_pc;
343→            }
344→
345→            Opcode::Shl => {
346→                // shl ra,rb - shift left
347→                let ra_val = cpu.get_reg(inst.ra);
348→                let shift = cpu.get_reg(inst.rb) & 0x1F;
349→                let result = CpuState::mask_24(ra_val << shift);
350→                cpu.set_reg(inst.ra, result);
351→                cpu.pc = next_pc;
352→            }
353→
354→            Opcode::Sra => {
355→                // sra ra,rb - shift right arithmetic
356→                let ra_val = cpu.get_reg(inst.ra);
357→                let shift = cpu.get_reg(inst.rb) & 0x1F;
358→                // Sign extend for arithmetic shift
359→                let signed_val = if ra_val & 0x800000 != 0 {
360→                    ra_val | 0xFF000000
361→                } else {
362→                    ra_val
363→                };
364→                let result = CpuState::mask_24((signed_val as i32 >> shift) as u32);
365→                cpu.set_reg(inst.ra, result);
366→                cpu.pc = next_pc;
367→            }
368→
369→            Opcode::Srl => {
370→                // srl ra,rb - shift right logical
371→                let ra_val = cpu.get_reg(inst.ra);
372→                let shift = cpu.get_reg(inst.rb) & 0x1F;
373→                let result = ra_val >> shift;
374→                cpu.set_reg(inst.ra, result);
375→                cpu.pc = next_pc;
376→            }
377→
378→            Opcode::Sub => {
379→                // sub ra,rb
380→                let ra_val = cpu.get_reg(inst.ra);
381→                let rb_val = cpu.get_reg(inst.rb);
382→                let result = CpuState::mask_24(ra_val.wrapping_sub(rb_val));
383→                cpu.set_reg(inst.ra, result);
384→                cpu.pc = next_pc;
385→            }
386→
387→            Opcode::SubSp => {
388→                // sub sp,dddddd
389→                let sp = cpu.get_reg(4);
390→                let result = CpuState::mask_24(sp.wrapping_sub(imm24));
391→                cpu.set_reg(4, result);
392→                cpu.pc = next_pc;
393→            }
394→
395→            Opcode::Sw => {
396→                // sw ra,dd(rb) - store word
397→                let base = cpu.get_reg(inst.rb);
398→                let offset = CpuState::sign_extend_8(imm8);
399→                let addr = CpuState::mask_24(base.wrapping_add(offset));
400→                let value = cpu.get_reg(inst.ra);
401→                cpu.write_word(addr, value);
402→                cpu.pc = next_pc;
403→            }
404→
405→            Opcode::Sxt => {
406→                // sxt ra,rb - sign extend byte
407→                let rb_val = cpu.get_reg(inst.rb);
408→                cpu.set_reg(inst.ra, CpuState::sign_extend_8(rb_val as u8));
409→                cpu.pc = next_pc;
410→            }
411→
412→            Opcode::Xor => {
413→                // xor ra,rb
414→                let ra_val = cpu.get_reg(inst.ra);
415→                let rb_val = cpu.get_reg(inst.rb);
416→                cpu.set_reg(inst.ra, ra_val ^ rb_val);
417→                cpu.pc = next_pc;
418→            }
419→
420→            Opcode::Zxt => {
421→                // zxt ra,rb - zero extend byte
422→                let rb_val = cpu.get_reg(inst.rb);
423→                cpu.set_reg(inst.ra, rb_val & 0xFF);
424→                cpu.pc = next_pc;
425→            }
426→
427→            Opcode::Invalid => {
428→                return ExecuteResult::InvalidInstruction(inst_byte);
429→            }
430→        }
431→
432→        cpu.cycles += 1;
433→        cpu.instructions += 1;
434→        cpu.uart_tick();
435→
436→        // Record trace entry
437→        cpu.trace.push(TraceEntry {
438→            pc: trace_pc,
439→            opcode: inst.opcode,
440→            ra: inst.ra,
441→            rb: inst.rb,
442→            size: inst_size as u8,
443→            imm8,
444→            imm24,
445→            regs_before: trace_regs_before,
446→            regs_after: cpu.registers,
447→            c_before: trace_c_before,
448→            c_after: cpu.c,
449→            sp_before: trace_sp_before,

