191→impl Component for Repl {
192→    type Message = Msg;
193→    type Properties = ();
194→
195→    fn create(ctx: &Context<Self>) -> Self {
196→        ctx.link().send_message(Msg::Init);
197→
198→        Self {
199→            emulator: {
200→                let mut emu = EmulatorCore::new();
201→                emu.set_uart_tx_busy_cycles(0); // instant TX in browser
202→                emu
203→            },
204→            output: String::new(),
205→            transcript: String::new(),
206→            uart_seen: 0,
207→            input: String::from("(+ 1 2)"),
208→            status: "Assembling interpreter...".into(),
209→            running: false,
210→            loaded: false,
211→            waiting_for_input: false,
212→            uart_tx_queue: VecDeque::new(),
213→            prelude: PreludeTier::Standard,
214→            stack_size: StackSize::ThreeKb,
215→            led_on: false,
216→            switch_pressed: false,
217→            view_mode: ViewMode::Cli,
218→            selected_demo: None,
219→            addr_heap_next: None,
220→            addr_sym_count: None,
221→            addr_str_pool_next: None,
222→            heap_used: 0,
223→            sym_used: 0,
224→            str_pool_used: 0,
225→            stack_depth: 0,
226→            cpu_load: 0.0,
227→            input_ref: NodeRef::default(),
228→            cli_input_ref: NodeRef::default(),
229→        }
230→    }
231→
232→    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
233→        match msg {
234→            Msg::Init => {
235→                self.load_binary();
236→                if self.loaded {
237→                    ctx.link().send_message(Msg::Tick);
238→                }
239→                true
240→            }
241→
242→            Msg::Tick => {
243→                if !self.running {
244→                    return false;
245→                }
246→
247→                // Feed queued bytes: poll-before-feed (match cor24-run).
248→                // Budget limits total instructions to avoid blocking the
249→                // browser when the interpreter is busy evaluating.
250→                let mut feed_budget: u32 = 10_000;
251→                while !self.uart_tx_queue.is_empty() && feed_budget > 0 {
252→                    let status = self.emulator.read_byte(0xFF0101);
253→                    if status & 0x01 != 0 {
254→                        // CPU hasn't consumed previous byte — run a bit more
255→                        self.emulator.run_batch(50);
256→                        feed_budget = feed_budget.saturating_sub(50);
257→                        continue;
258→                    }
259→                    let byte = self.uart_tx_queue.pop_front().unwrap();
260→                    self.emulator.send_uart_byte(byte);
261→                    self.emulator.run_batch(50);
262→                    feed_budget = feed_budget.saturating_sub(50);
263→                    if byte == b'\n' {
264→                        break;
265→                    }
266→                }
267→
268→                let result = self.emulator.run_batch(BATCH_SIZE);
269→
270→                // EWMA of CPU utilization: how much of the batch budget was used
271→                let utilization = result.instructions_run as f64 / BATCH_SIZE as f64;
272→                const ALPHA: f64 = 0.15; // smoothing factor
273→                self.cpu_load = self.cpu_load * (1.0 - ALPHA) + utilization * ALPHA;
274→
275→                if result.led_changed {
276→                    self.led_on = self.emulator.get_led() & 1 != 0;
277→                }
278→
279→                // Sample memory usage from runtime globals
280→                if let Some(addr) = self.addr_heap_next {
281→                    self.heap_used = self.emulator.read_word(addr);
282→                }
283→                if let Some(addr) = self.addr_sym_count {
284→                    self.sym_used = self.emulator.read_word(addr);
285→                }
286→                if let Some(addr) = self.addr_str_pool_next {
287→                    self.str_pool_used = self.emulator.read_word(addr);
288→                }
289→                let sp = self.emulator.get_reg(4);
290→                self.stack_depth = self.stack_size.initial_sp().saturating_sub(sp);
291→
292→                let uart = self.emulator.get_uart_output();
293→                // Append new UART bytes to transcript (CLI view)
294→                if uart.len() > self.uart_seen {
295→                    self.transcript.push_str(&uart[self.uart_seen..]);
296→                    self.uart_seen = uart.len();
297→                }
298→                // Update raw output (Split view)
299→                let uart_owned = uart.to_string();
300→                if uart_owned != self.output {
301→                    self.output = uart_owned;
302→                }
303→
304→                match result.reason {
305→                    StopReason::CycleLimit => {
306→                        let at_prompt =
307→                            self.uart_tx_queue.is_empty() && self.output.ends_with("> ");
308→
309→                        if at_prompt {
310→                            self.running = false;
311→                            self.waiting_for_input = true;
312→                            self.cpu_load = 0.0;
313→                            self.status = "Ready.".into();
314→                        } else {
315→                            let link = ctx.link().clone();
316→                            Timeout::new(25, move || link.send_message(Msg::Tick)).forget();
317→                        }
318→                    }
319→                    StopReason::Halted => {
320→                        self.running = false;
321→                        self.waiting_for_input = false;
322→                        self.cpu_load = 0.0;
323→                        self.status = "Program finished.".into();
324→                    }
325→                    StopReason::InvalidInstruction(byte) => {
326→                        self.running = false;
327→                        self.status = format!(
328→                            "Invalid instruction 0x{:02X} at PC=0x{:06X}",
329→                            byte,
330→                            self.emulator.pc()
331→                        );
332→                    }
333→                    StopReason::Breakpoint(addr) => {
334→                        self.running = false;
335→                        self.status = format!("Breakpoint at 0x{:06X}", addr);
336→                    }
337→                    StopReason::Paused => {
338→                        self.running = false;
339→                        self.status = "Paused.".into();
340→                    }
341→                }
342→                true
343→            }
344→
345→            Msg::InputChanged(value) => {
346→                self.input = value;
347→                false
348→            }
349→
350→            Msg::Eval => {
351→                if !self.loaded {
352→                    return true;
353→                }
354→                // Echo input to transcript (CLI view shows interleaved I/O)
355→                for line in self.input.lines() {
356→                    if !line.trim().is_empty() {
357→                        self.transcript.push_str(line);
358→                        self.transcript.push('\n');
359→                    }
360→                }
361→                self.send_input();
362→                self.status = "Evaluating...".into();
363→                self.waiting_for_input = false;
364→                if !self.running {
365→                    self.emulator.resume();
366→                    self.running = true;
367→                    ctx.link().send_message(Msg::Tick);
368→                }
369→                // In CLI mode, clear the input after sending
370→                if self.view_mode == ViewMode::Cli {
371→                    self.input.clear();
372→                }
373→                true
374→            }
375→
376→            Msg::CliKeyDown(e) => {
377→                if e.key() == "Enter" && !e.shift_key() {
378→                    e.prevent_default();
379→                    ctx.link().send_message(Msg::Eval);
380→                }
381→                false
382→            }
383→
384→            Msg::SetPrelude(tier) => {
385→                if tier != self.prelude {
386→                    self.prelude = tier;
387→                    self.running = false;
388→                    self.load_binary();
389→                    if self.loaded {
390→                        ctx.link().send_message(Msg::Tick);
391→                    }
392→                }
393→                true
394→            }
395→
396→            Msg::SetStack(size) => {
397→                if size != self.stack_size {
398→                    self.stack_size = size;
399→                    self.running = false;
400→                    self.load_binary();
401→                    if self.loaded {
402→                        ctx.link().send_message(Msg::Tick);
403→                    }
404→                }
405→                true
406→            }
407→
408→            Msg::Reset => {
409→                self.running = false;
410→                self.load_binary();
411→                if self.loaded {
412→                    ctx.link().send_message(Msg::Tick);
413→                }
414→                true
415→            }
416→
417→            Msg::LoadDemo(index) => {
418→                if let Some(demo) = DEMOS.get(index) {
419→                    self.selected_demo = Some(index);
420→                    self.input = demo.source.trim().to_string();
421→                    self.prelude = demo.prelude;
422→                    self.stack_size = demo.stack;
423→                    // Always reset emulator for a clean demo run
424→                    self.running = false;
425→                    self.load_binary();
426→                    if self.loaded {
427→                        ctx.link().send_message(Msg::Tick);
428→                    }
429→                    // Switch to Split view for demos (multi-line code)
430→                    self.view_mode = ViewMode::Split;
431→                }
432→                true
433→            }
434→
435→            Msg::ToggleView => {
436→                self.view_mode = match self.view_mode {
437→                    ViewMode::Cli => ViewMode::Split,
438→                    ViewMode::Split => ViewMode::Cli,
439→                };
440→                true
441→            }
442→
443→            Msg::ToggleSwitch => {
444→                self.switch_pressed = !self.switch_pressed;
445→                self.emulator.set_button_pressed(self.switch_pressed);
446→                true
447→            }
448→
449→            Msg::ClearAll => {
450→                self.emulator.clear_uart_output();
451→                self.output.clear();
452→                self.transcript.clear();
453→                self.uart_seen = 0;
454→                self.input.clear();
455→                self.selected_demo = None;
456→                true
457→            }
458→
459→            Msg::PauseResume => {
460→                if self.running {
461→                    // Pause
462→                    self.running = false;
463→                    self.status = "Paused.".into();
464→                } else if self.loaded {
465→                    // Resume
466→                    self.emulator.resume();
467→                    self.running = true;
468→                    self.waiting_for_input = false;
469→                    self.status = "Running...".into();
470→                    ctx.link().send_message(Msg::Tick);
471→                }
472→                true
473→            }
474→        }
475→    }
476→
477→    fn view(&self, ctx: &Context<Self>) -> Html {
478→        let on_eval = ctx.link().callback(|_| Msg::Eval);
479→        let on_reset = ctx.link().callback(|_| Msg::Reset);
480→        let on_toggle_view = ctx.link().callback(|_| Msg::ToggleView);
481→        let on_toggle_switch = ctx.link().callback(|_| Msg::ToggleSwitch);
482→        let on_clear = ctx.link().callback(|_| Msg::ClearAll);
483→        let on_pause = ctx.link().callback(|_| Msg::PauseResume);
484→
485→        let on_prelude = ctx.link().callback(|e: Event| {
486→            let target: web_sys::HtmlSelectElement = e.target_unchecked_into();
487→            let tier = match target.value().as_str() {
488→                "bare" => PreludeTier::Bare,
489→                "minimal" => PreludeTier::Minimal,
490→                "full" => PreludeTier::Full,
491→                "scheme" => PreludeTier::Scheme,
492→                _ => PreludeTier::Standard,
493→            };
494→            Msg::SetPrelude(tier)
495→        });
496→
497→        let on_stack = ctx.link().callback(|e: Event| {
