499→            let size = match target.value().as_str() {
500→                "8" => StackSize::EightKb,
501→                _ => StackSize::ThreeKb,
502→            };
503→            Msg::SetStack(size)
504→        });
505→
506→        let on_demo = ctx.link().callback(|e: Event| {
507→            let target: web_sys::HtmlSelectElement = e.target_unchecked_into();
508→            let idx: usize = target.value().parse().unwrap_or(usize::MAX);
509→            Msg::LoadDemo(idx)
510→        });
511→
512→        let eval_disabled = (!self.waiting_for_input && self.running) || !self.loaded;
513→        let show_spinner = self.running && !self.waiting_for_input;
514→        let view_label = match self.view_mode {
515→            ViewMode::Cli => "Split",
