522→                <div class="toolbar">
523→                    <label class="toolbar-item">
524→                        {"Prelude"}
525→                        <select onchange={on_prelude}>
526→                            { for PreludeTier::ALL.iter().map(|t| {
527→                                let val = match t {
528→                                    PreludeTier::Bare => "bare",
529→                                    PreludeTier::Minimal => "minimal",
530→                                    PreludeTier::Standard => "standard",
531→                                    PreludeTier::Full => "full",
532→                                    PreludeTier::Scheme => "scheme",
533→                                };
534→                                html! {
535→                                    <option value={val} selected={*t == self.prelude}>
536→                                        { t.label() }
537→                                    </option>
538→                                }
539→                            })}
540→                        </select>
541→                    </label>
542→                    <label class="toolbar-item">
543→                        {"Stack"}
544→                        <select onchange={on_stack}>
545→                            { for StackSize::ALL.iter().map(|s| {
546→                                let val = match s {
547→                                    StackSize::ThreeKb => "3",
548→                                    StackSize::EightKb => "8",
549→                                };
550→                                html! {
551→                                    <option value={val} selected={*s == self.stack_size}>
552→                                        { s.label() }
553→                                    </option>
554→                                }
555→                            })}
556→                        </select>
557→                    </label>
558→                    <label class="toolbar-item">
559→                        {"Demo"}
560→                        <select onchange={on_demo}>
561→                            <option value="" selected={self.selected_demo.is_none()}>{"— select —"}</option>
562→                            { for PreludeTier::ALL.iter().filter(|tier| {
563→                                DEMOS.iter().any(|d| d.prelude == **tier)
564→                            }).map(|tier| {
