102→/// A single instruction execution record
103→#[derive(Clone, Debug)]
104→pub struct TraceEntry {
105→    /// Program counter at start of instruction
106→    pub pc: u32,
107→    /// Decoded opcode
108→    pub opcode: Opcode,
109→    /// Destination register index
110→    pub ra: u8,
111→    /// Source register index
112→    pub rb: u8,
113→    /// Instruction size in bytes (1, 2, or 4)
114→    pub size: u8,
115→    /// 8-bit immediate (for 2-byte and 4-byte instructions)
116→    pub imm8: u8,
117→    /// 24-bit immediate (for 4-byte instructions)
118→    pub imm24: u32,
119→    /// Register state before execution
120→    pub regs_before: [u32; 8],
121→    /// Register state after execution
122→    pub regs_after: [u32; 8],
123→    /// Condition flag before
124→    pub c_before: bool,
125→    /// Condition flag after
126→    pub c_after: bool,
127→    /// SP before (convenience, same as regs_before\[4\])
128→    pub sp_before: u32,
129→    /// Instruction count at this point
130→    pub instruction_num: u64,
131→}
132→
133→/// Register names for display
134→const REG_NAMES: [&str; 8] = ["r0", "r1", "r2", "fp", "sp", "z/c", "iv", "ir"];
135→
136→impl fmt::Display for TraceEntry {
137→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
138→        // Disassemble the instruction
139→        let disasm = self.disassemble();
140→
141→        write!(
142→            f,
143→            "{:5} 0x{:06X}  {:<24}",
144→            self.instruction_num, self.pc, disasm
145→        )?;
146→
147→        // Show register changes
148→        let mut changes = Vec::new();
149→        for (i, name) in REG_NAMES.iter().enumerate() {
150→            if self.regs_before[i] != self.regs_after[i] {
151→                changes.push(format!(
152→                    "{}:0x{:06X}→0x{:06X}",
153→                    name, self.regs_before[i], self.regs_after[i]
154→                ));
155→            }
156→        }
157→        if self.c_before != self.c_after {
158→            changes.push(format!("c:{}→{}", self.c_before as u8, self.c_after as u8));
159→        }
160→        if !changes.is_empty() {
161→            write!(f, "  [{}]", changes.join(" "))?;
162→        }
163→
164→        Ok(())
165→    }
166→}
167→
168→impl TraceEntry {
169→    /// Disassemble this instruction into a human-readable string
170→    pub fn disassemble(&self) -> String {
171→        let ra = REG_NAMES[self.ra as usize];
172→        let rb = REG_NAMES[self.rb as usize];
173→        match self.opcode {
174→            Opcode::AddReg => format!("add     {},{}", ra, rb),
175→            Opcode::AddImm => format!("add     {},{}", ra, self.imm8 as i8),
176→            Opcode::And => format!("and     {},{}", ra, rb),
177→            Opcode::Bra => {
178→                let offset = self.imm8 as i8;
179→                let target = (self.pc as i64 + 4 + offset as i64) as u32 & 0xFFFFFF;
180→                format!("bra     0x{:06X}", target)
181→            }
182→            Opcode::Brf => {
183→                let offset = self.imm8 as i8;
184→                let target = (self.pc as i64 + 4 + offset as i64) as u32 & 0xFFFFFF;
185→                format!("brf     0x{:06X}", target)
186→            }
187→            Opcode::Brt => {
188→                let offset = self.imm8 as i8;
189→                let target = (self.pc as i64 + 4 + offset as i64) as u32 & 0xFFFFFF;
190→                format!("brt     0x{:06X}", target)
191→            }
