.repl-container {
    display: flex;
    flex-direction: column;
    flex: 1;
    overflow: hidden;
    padding: 8px 20px;
    gap: 8px;
    min-height: 0;
}

/* Toolbar */
.toolbar {
    display: flex;
    align-items: center;
    gap: 10px;
    flex-wrap: wrap;
    flex-shrink: 0;
}
.toolbar-item {
    display: flex;
    align-items: center;
    gap: 5px;
    font-size: 14px;
    font-weight: 600;
    color: var(--text);
}
.toolbar-item select {
    background: var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 4px 8px;
    font-family: var(--mono);
    font-size: 13px;
    cursor: pointer;
}
.toolbar-item select:focus {
    border-color: var(--accent);
    outline: none;
}
.toolbar-btn {
    background: var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 4px 12px;
    font-family: var(--mono);
    font-size: 13px;
    cursor: pointer;
}
.toolbar-btn:hover {
    border-color: var(--accent);
}
.toolbar-desc {
    font-size: 13px;
    color: var(--dim);
    margin-left: auto;
}

/* Main area — relative for floating overlays */
.main-area {
    position: relative;
    flex: 1;
    min-height: 0;
    display: flex;
    flex-direction: column;
}

/* Output — always full size */
.output {
    flex: 1;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 12px;
    overflow-y: auto;
    font-size: 15px;
    line-height: 1.5;
    color: var(--green);
    white-space: pre-wrap;
    word-break: break-all;
    margin: 0;
    min-height: 0;
}

/* ─── Floating hardware panel (top-right) ─── */
.hw-float {
    position: absolute;
    top: 8px;
    right: 8px;
    z-index: 10;
    background: rgba(30, 30, 46, 0.85);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 8px 12px;
    display: flex;
    flex-direction: column;
    gap: 8px;
}
.hw-row {
    display: flex;
    align-items: center;
    gap: 8px;
}
.hw-label {
    font-size: 12px;
    font-weight: 600;
    color: var(--dim);
    min-width: 22px;
}

.led {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    transition: all 0.15s;
}
.led-off {
    background: #333;
    box-shadow: inset 0 2px 4px rgba(0,0,0,0.5);
}
.led-on {
    background: radial-gradient(circle at 30% 30%, #ff5555, #ff0000, #cc0000);
    box-shadow: 0 0 12px #ff0000, 0 0 24px rgba(255,0,0,0.3);
}

.switch {
    width: 22px;
    height: 22px;
    border-radius: 4px;
    cursor: pointer;
    transition: all 0.15s;
}
.switch-off {
    background: linear-gradient(to bottom, #444, #222);
    border: 1px solid #555;
}
.switch-on {
    background: linear-gradient(to bottom, #00d9ff, #0099cc);
    border: 1px solid #00d9ff;
    box-shadow: 0 0 8px rgba(0, 217, 255, 0.4);
}
.switch:hover {
    transform: scale(1.1);
}
.switch:active {
    transform: scale(0.95);
}

.hw-sep {
    border-top: 1px solid var(--border);
    margin: 2px 0;
}

/* Memory gauges */
.gauge-row {
    display: flex;
    align-items: center;
    gap: 6px;
}
.gauge-label {
    font-size: 11px;
    color: var(--dim);
    min-width: 32px;
}
.gauge-track {
    width: 60px;
    height: 8px;
    background: #222;
    border-radius: 4px;
    overflow: hidden;
}
.gauge-fill {
    height: 100%;
    border-radius: 4px;
    transition: width 0.3s, background 0.3s;
}
.gauge-green  { background: #a6e3a1; }
.gauge-yellow { background: #f9e2af; }
.gauge-red    { background: #f38ba8; }
.gauge-text {
    font-size: 10px;
    color: var(--dim);
    white-space: nowrap;
}

/* ─── CLI view: single-line input bar at bottom ─── */
.cli-input-bar {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 6px 0;
    flex-shrink: 0;
}
.cli-prompt {
    font-size: 15px;
    color: var(--green);
    font-weight: 600;
}
.cli-input {
    flex: 1;
    background: transparent;
    border: none;
    border-bottom: 1px solid var(--border);
    color: var(--text);
    font-family: var(--mono);
    font-size: 15px;
    padding: 4px 0;
    outline: none;
}
.cli-input:focus {
    border-bottom-color: var(--accent);
}
.cli-input:disabled {
    opacity: 0.4;
}
.cli-status {
    font-size: 12px;
    color: var(--dim);
    white-space: nowrap;
}

/* ─── Split view: semi-transparent overlay (bottom-right 1/4) ─── */
.split-input-overlay {
    position: absolute;
    bottom: 8px;
    right: 8px;
    width: 50%;
    height: 50%;
    z-index: 5;
    background: rgba(40, 40, 64, 0.88);
    border: 2px dashed rgba(249, 226, 175, 0.5);
    border-radius: 6px;
    display: flex;
    flex-direction: column;
    padding: 10px;
    gap: 8px;
    backdrop-filter: blur(4px);
}
.split-textarea {
    flex: 1;
    background: transparent;
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 10px;
    color: var(--text);
    font-family: var(--mono);
    font-size: 14px;
    line-height: 1.5;
    resize: none;
    outline: none;
    min-height: 0;
}
.split-textarea:focus {
    border-color: var(--accent);
}
.split-controls {
    display: flex;
    align-items: center;
    gap: 10px;
    flex-shrink: 0;
}
.eval-btn {
    background: var(--accent);
    color: var(--bg);
    border: none;
    border-radius: 4px;
    padding: 5px 16px;
    font-family: var(--mono);
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
}
.eval-btn:hover:not(:disabled) {
    filter: brightness(1.1);
}
.eval-btn:disabled {
    opacity: 0.4;
    cursor: not-allowed;
}
.status {
    font-size: 12px;
    color: var(--dim);
}

/* Animated spinner (visible while Eval is disabled/running) */
.spinner {
    display: inline-block;
    width: 14px;
    height: 14px;
    border: 2px solid var(--border);
    border-top-color: var(--accent);
    border-radius: 50%;
    animation: spin 0.8s linear infinite;
}
@keyframes spin {
    to { transform: rotate(360deg); }
}

